class Solution {
    public int lengthOfLongestSubstring(String s) {
        int maxLength = 0;
        for (int i = 0; i < s.length(); i++) {
            java.util.Set<Character> seen = new java.util.HashSet<>();
            int j = i;
            while (j < s.length() && !seen.contains(s.charAt(j))) {
                seen.add(s.charAt(j));
                j++;
            }
            maxLength = Math.max(maxLength, j - i);
        }
        return maxLength;
    }
}

class Solution {
    public int lengthOfLongestSubstring(String s) {
        java.util.Set<Character> window = new java.util.HashSet<>();
        int left = 0, maxLength = 0;

        for (int right = 0; right < s.length(); right++) {
            char c = s.charAt(right);
            while (window.contains(c)) {
                window.remove(s.charAt(left));
                left++;
            }
            window.add(c);
            maxLength = Math.max(maxLength, right - left + 1);
        }
        return maxLength;
    }
}

class Solution {
    public boolean checkInclusion(String s1, String s2) {
        int n = s1.length();
        char[] sorted1 = s1.toCharArray();
        java.util.Arrays.sort(sorted1);

        for (int i = 0; i + n <= s2.length(); i++) {
            char[] window = s2.substring(i, i + n).toCharArray();
            java.util.Arrays.sort(window);
            if (java.util.Arrays.equals(sorted1, window)) {
                return true;
            }
        }
        return false;
    }
}

class Solution {
    public boolean checkInclusion(String s1, String s2) {
        int n = s1.length(), m = s2.length();
        if (n > m) return false;

        int[] s1Count = new int[26];
        int[] windowCount = new int[26];

        for (int i = 0; i < n; i++) {
            s1Count[s1.charAt(i) - 'a']++;
            windowCount[s2.charAt(i) - 'a']++;
        }

        if (java.util.Arrays.equals(s1Count, windowCount)) return true;

        for (int i = n; i < m; i++) {
            windowCount[s2.charAt(i) - 'a']++;
            windowCount[s2.charAt(i - n) - 'a']--;
            if (java.util.Arrays.equals(s1Count, windowCount)) return true;
        }
        return false;
    }
}

