class Solution {
    public java.util.List<Integer> findAnagrams(String s, String p) {
        java.util.List<Integer> result = new java.util.ArrayList<>();
        int n = p.length(), m = s.length();
        if (n > m) return result;

        int[] pCount = new int[26];
        int[] windowCount = new int[26];

        for (int i = 0; i < n; i++) {
            pCount[p.charAt(i) - 'a']++;
            windowCount[s.charAt(i) - 'a']++;
        }

        if (java.util.Arrays.equals(pCount, windowCount)) result.add(0);

        for (int i = n; i < m; i++) {
            windowCount[s.charAt(i) - 'a']++;
            windowCount[s.charAt(i - n) - 'a']--;
            if (java.util.Arrays.equals(pCount, windowCount)) {
                result.add(i - n + 1);
            }
        }
        return result;
    }
}

class Solution {
    public int characterReplacement(String s, int k) {
        int maxLength = 0;
        for (int i = 0; i < s.length(); i++) {
            int[] count = new int[26];
            int maxFreq = 0;
            for (int j = i; j < s.length(); j++) {
                count[s.charAt(j) - 'A']++;
                maxFreq = Math.max(maxFreq, count[s.charAt(j) - 'A']);
                int windowLength = j - i + 1;
                if (windowLength - maxFreq <= k) {
                    maxLength = Math.max(maxLength, windowLength);
                }
            }
        }
        return maxLength;
    }
}

class Solution {
    public int characterReplacement(String s, int k) {
        int[] count = new int[26];
        int left = 0, maxFreq = 0, maxLength = 0;

        for (int right = 0; right < s.length(); right++) {
            count[s.charAt(right) - 'A']++;
            maxFreq = Math.max(maxFreq, count[s.charAt(right) - 'A']);

            while ((right - left + 1) - maxFreq > k) {
                count[s.charAt(left) - 'A']--;
                left++;
            }
            maxLength = Math.max(maxLength, right - left + 1);
        }
        return maxLength;
    }
}

class Solution {
    public String minWindow(String s, String t) {
        String best = "";
        for (int i = 0; i < s.length(); i++) {
            for (int j = i; j < s.length(); j++) {
                String candidate = s.substring(i, j + 1);
                if (contains(candidate, t) && (best.isEmpty() || candidate.length() < best.length())) {
                    best = candidate;
                }
            }
        }
        return best;
    }

    private boolean contains(String candidate, String t) {
        int[] need = new int[128];
        for (char c : t.toCharArray()) need[c]++;
        for (char c : candidate.toCharArray()) need[c]--;
        for (int n : need) if (n > 0) return false;
        return true;
    }
}

class Solution {
    public String minWindow(String s, String t) {
        int[] need = new int[128];
        for (char c : t.toCharArray()) need[c]++;

        int required = t.length();
        int left = 0, bestStart = 0, bestLength = Integer.MAX_VALUE;

        for (int right = 0; right < s.length(); right++) {
            char c = s.charAt(right);
            if (need[c] > 0) required--;
            need[c]--;

            while (required == 0) {
                if (right - left + 1 < bestLength) {
                    bestLength = right - left + 1;
                    bestStart = left;
                }
                char leftChar = s.charAt(left);
                need[leftChar]++;
                if (need[leftChar] > 0) required++;
                left++;
            }
        }
        return bestLength == Integer.MAX_VALUE ? "" : s.substring(bestStart, bestStart + bestLength);
    }
}

class Solution {
    public int[] maxSlidingWindow(int[] nums, int k) {
        int[] result = new int[nums.length - k + 1];
        for (int i = 0; i <= nums.length - k; i++) {
            int max = nums[i];
            for (int j = i; j < i + k; j++) {
                max = Math.max(max, nums[j]);
            }
            result[i] = max;
        }
        return result;
    }
}

class Solution {
    public int[] maxSlidingWindow(int[] nums, int k) {
        int[] result = new int[nums.length - k + 1];
        java.util.Deque<Integer> deque = new java.util.ArrayDeque<>();

        for (int i = 0; i < nums.length; i++) {
            if (!deque.isEmpty() && deque.peekFirst() <= i - k) {
                deque.pollFirst();
            }
            while (!deque.isEmpty() && nums[deque.peekLast()] < nums[i]) {
                deque.pollLast();
            }
            deque.offerLast(i);

            if (i >= k - 1) {
                result[i - k + 1] = nums[deque.peekFirst()];
            }
        }
        return result;
    }
}

